/**
 * 배열에서 중복을 제거하면서 원래 순서를 유지합니다.
 * @param arr - 입력 배열
 * @param keyFn - 중복 판별 키 추출 함수 (기본: identity)
 */
export function uniqueBy<T>(
  arr: T[],
  keyFn: (item: T) => unknown = (item) => item,
): T[] {
  const seen = new Set<unknown>();
  return arr.filter((item) => {
    const key = keyFn(item);
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

// 사용 예시
const numbers = [1, 2, 2, 3, 1, 4];
uniqueBy(numbers); // [1, 2, 3, 4]

const users = [
  { id: 1, name: 'Alice' },
  { id: 2, name: 'Bob' },
  { id: 1, name: 'Alice (dup)' },
];
uniqueBy(users, u => u.id); // [{ id: 1, ... }, { id: 2, ... }]
```
